 71			if errors.As(runErr, &exitErr) {
 72				exitCode = exitErr.ExitCode()
 73			} else {
 74				exitCode = 1
 75			}
 76		}
 77		if result.Metric != nil {
 78			result.Metric.Status = metricStatusForRun(status)
 79			if status == StatusSuccess {
