216	var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)
217	
218	func normalizeMeasurement(stdout string) (float64, string) {
219		trimmed := strings.TrimSpace(stdout)
220		if trimmed == "" {
221			return 0, ""
222		}
223		if value, unit, ok := parseJSONMeasurement(trimmed); ok {
224			return value, unit
225		}
226		if value, unit, ok := parseTextMeasurement(trimmed); ok {
227			return value, unit
228		}
229		return 0, ""
230	}
231	
232	func parseJSONMeasurement(text string) (float64, string, bool) {
233		var obj map[string]any
234		if err := json.Unmarshal([]byte(text), &obj); err != nil {
235			return 0, "", false
236		}
237		if raw, ok := obj["value"]; ok {
238			switch v := raw.(type) {
239			case float64:
240				unit, _ := obj["unit"].(string)
241				return v, unit, true
242			case string:
243				if parsed, err := strconv.ParseFloat(v, 64); err == nil {
244					unit, _ := obj["unit"].(string)
245					return parsed, unit, true
246				}
247			}
248		}
249		return 0, "", false
250	}
251	
252	func parseTextMeasurement(text string) (float64, string, bool) {
253		match := measurementPattern.FindStringSubmatch(text)
254		if len(match) < 2 {
255			return 0, "", false
256		}
257		value, err := strconv.ParseFloat(match[1], 64)
258		if err != nil {
259			return 0, "", false
260		}
261		unit := ""
262		if len(match) >= 3 {
263			unit = strings.ToLower(match[2])
264		}
265		return value, unit, true
266	}
