119	func (s *Store) saveDefinitionBead(def Definition) error {
120		if s.DefinitionCollection == nil {
121			return fmt.Errorf("exec definition collection not initialized")
122		}
123		return s.DefinitionCollection.WithLock(func() error {
124			beads, err := s.DefinitionCollection.ReadAll()
125			if err != nil {
126				return err
127			}
128			current := definitionBead(def)
129			replaced := false
130			for i := range beads {
131				if beads[i].ID == current.ID {
132					beads[i] = current
133					replaced = true
134					break
135				}
136			}
137			if !replaced {
138				beads = append(beads, current)
139			}
140			return s.DefinitionCollection.WriteAll(beads)
141		})
142	}
