144	func (s *Store) saveRunRecord(rec RunRecord) error {
145		if s.RunCollection == nil {
146			return fmt.Errorf("exec run collection not initialized")
147		}
148		if rec.RunID == "" {
149			return fmt.Errorf("run_id is required")
150		}
151		if rec.DefinitionID == "" {
152			return fmt.Errorf("definition_id is required")
153		}
154		if rec.Attachments == nil {
155			rec.Attachments = make(map[string]string)
156		}
157		rec.Attachments["stdout"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stdout.log")
158		rec.Attachments["stderr"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stderr.log")
159		rec.Attachments["result"] = runAttachmentRef(s.WorkingDir, rec.RunID, "result.json")
160	
161		attachmentRoot := filepath.Join(s.WorkingDir, ".ddx", execRunAttachmentDir)
162		if err := os.MkdirAll(attachmentRoot, 0o755); err != nil {
163			return err
164		}
165		tempDir, err := os.MkdirTemp(attachmentRoot, ".tmp-")
166		if err != nil {
167			return err
168		}
169		defer os.RemoveAll(tempDir)
170	
171		manifestRaw, err := json.MarshalIndent(rec.RunManifest, "", "  ")
172		if err != nil {
173			return err
174		}
175		resultRaw, err := json.MarshalIndent(rec.Result, "", "  ")
176		if err != nil {
177			return err
178		}
179		if err := os.WriteFile(filepath.Join(tempDir, "manifest.json"), manifestRaw, 0o644); err != nil {
180			return err
181		}
182		if err := os.WriteFile(filepath.Join(tempDir, "result.json"), resultRaw, 0o644); err != nil {
183			return err
184		}
185		if err := os.WriteFile(filepath.Join(tempDir, "stdout.log"), []byte(rec.Result.Stdout), 0o644); err != nil {
186			return err
187		}
188		if err := os.WriteFile(filepath.Join(tempDir, "stderr.log"), []byte(rec.Result.Stderr), 0o644); err != nil {
189			return err
190		}
191		if err := syncPath(tempDir); err != nil {
192			return err
193		}
194	
195		return s.RunCollection.WithLock(func() error {
196			finalDir := filepath.Join(attachmentRoot, rec.RunID)
197			if err := os.Rename(tempDir, finalDir); err != nil {
198				return err
199			}
200			if err := syncPath(attachmentRoot); err != nil {
201				return err
202			}
203			beads, err := s.RunCollection.ReadAll()
204			if err != nil {
205				return err
206			}
207			current := runBead(rec)
208			replaced := false
209			for i := range beads {
210				if beads[i].ID == current.ID {
211					beads[i] = current
212					replaced = true
213					break
214				}
215			}
216			if !replaced {
217				beads = append(beads, current)
218			}
219			return s.RunCollection.WriteAll(beads)
220		})
221	}
