 16	// execPromptCapBytes caps the size of inline prompt env-var values
 17	// (DDX_AGENT_PROMPT) carried by exec definitions. FEAT-022 §9 / Stage D2.
 18	// Package-level variable so tests can lower the cap; production callers
 19	// must not mutate it.
 20	var execPromptCapBytes = evidence.DefaultMaxPromptBytes
 21	
 22	// loadDefinitions returns all definitions and the doc graph built during loading.
 23	// The graph may be nil if graph loading failed (soft error treated as empty).
 24	func (s *Store) loadDefinitions() ([]Definition, *docgraph.Graph, error) {
 25		defs := make(map[string]Definition)
 26	
 27		// Graph-authored definitions take precedence over runtime-managed ones.
 28		// The graph is returned so callers can reuse it without a second build.
 29		graph, graphDefs, _ := s.loadGraphDefinitions()
 30		for _, def := range graphDefs {
 31			if def.ID == "" || !def.Active {
 32				continue
 33			}
 34			defs[def.ID] = def
 35		}
 36	
 37		if s.DefinitionCollection != nil {
 38			beads, err := s.DefinitionCollection.ReadAll()
 39			if err != nil {
 40				return nil, nil, err
 41			}
 42			for _, entry := range beads {
 43				def, err := definitionFromBead(entry)
 44				if err != nil {
 45					return nil, nil, err
 46				}
 47				if def.ID == "" || !def.Active {
 48					continue
 49				}
 50				if _, ok := defs[def.ID]; ok {
 51					continue // graph-authored takes precedence
 52				}
 53				defs[def.ID] = def
 54			}
 55		}
 56	
 57		legacy, err := s.readLegacyDefinitions()
 58		if err != nil {
 59			return nil, nil, err
 60		}
 61		for _, def := range legacy {
 62			if def.ID == "" || !def.Active {
 63				continue
 64			}
 65			if _, ok := defs[def.ID]; ok {
 66				continue
 67			}
 68			defs[def.ID] = def
 69		}
 70	
 71		out := make([]Definition, 0, len(defs))
 72		for _, def := range defs {
 73			if prompt, ok := def.Executor.Env["DDX_AGENT_PROMPT"]; ok {
 74				if observed := len([]byte(prompt)); observed > execPromptCapBytes {
 75					return nil, nil, fmt.Errorf(
 76						"exec definition %q env DDX_AGENT_PROMPT exceeds cap: observed %d bytes, cap %d bytes (configurable via .ddx/config.yaml:evidence_caps.max_prompt_bytes)",
 77						def.ID, observed, execPromptCapBytes)
 78				}
 79			}
 80			out = append(out, def)
 81		}
 82		sort.Slice(out, func(i, j int) bool {
 83			if out[i].CreatedAt.Equal(out[j].CreatedAt) {
 84				return out[i].ID < out[j].ID
 85			}
 86			return out[i].CreatedAt.After(out[j].CreatedAt)
 87		})
 88		return out, graph, nil
 89	}
