 91	// loadGraphDefinitions builds the doc graph and extracts exec definitions
 92	// embedded in document frontmatter via the exec: block.
 93	// Returns the built graph so callers can reuse it without a second walk.
 94	func (s *Store) loadGraphDefinitions() (*docgraph.Graph, []Definition, error) {
 95		graph, err := s.buildGraph()
 96		if err != nil {
 97			return nil, nil, err
 98		}
 99		var defs []Definition
100		for _, doc := range graph.Documents {
101			if doc.ExecDef == nil {
102				continue
103			}
104			ed := doc.ExecDef
105			// ArtifactIDs: prefer the explicit list; fall back to the document's depends_on.
106			artifactIDs := append([]string{}, ed.ArtifactIDs...)
107			if len(artifactIDs) == 0 {
108				artifactIDs = append(artifactIDs, doc.DependsOn...)
109			}
110			def := Definition{
111				ID:          doc.ID,
112				ArtifactIDs: artifactIDs,
113				Executor: ExecutorSpec{
114					Kind:      ed.Kind,
115					Command:   ed.Command,
116					Cwd:       ed.Cwd,
117					Env:       ed.Env,
118					TimeoutMS: ed.TimeoutMS,
119				},
120				Required:    ed.Required,
121				Active:      ed.Active,
122				GraphSource: true,
123			}
124			if ed.Comparison != "" || ed.Thresholds != nil {
125				def.Evaluation = Evaluation{Comparison: ed.Comparison}
126				if ed.Thresholds != nil {
127					def.Evaluation.Thresholds = Thresholds{
128						WarnMS:    ed.Thresholds.Warn,
129						RatchetMS: ed.Thresholds.Ratchet,
130					}
131				}
132			}
133			if ed.Metric != nil {
134				def.Result.Metric = &MetricResultSpec{
135					Unit: ed.Metric.Unit,
136				}
137			}
138			defs = append(defs, def)
139		}
140		return graph, defs, nil
141	}
