143	func (s *Store) readLegacyDefinitions() ([]Definition, error) {
144		entries, err := os.ReadDir(s.DefinitionsDir)
145		if err != nil {
146			if os.IsNotExist(err) {
147				return nil, nil
148			}
149			return nil, err
150		}
151	
152		defs := make([]Definition, 0, len(entries))
153		for _, entry := range entries {
154			if entry.IsDir() || !strings.HasSuffix(strings.ToLower(entry.Name()), ".json") {
155				continue
156			}
157			raw, err := os.ReadFile(filepath.Join(s.DefinitionsDir, entry.Name()))
158			if err != nil {
159				return nil, err
160			}
161			var def Definition
162			if err := json.Unmarshal(raw, &def); err != nil {
163				return nil, fmt.Errorf("parse exec definition %q: %w", entry.Name(), err)
164			}
165			defs = append(defs, def)
166		}
167		return defs, nil
168	}
