170	func (s *Store) loadRuns() ([]RunRecord, error) {
171		runs := make(map[string]RunRecord)
172	
173		if s.RunCollection != nil {
174			beads, err := s.RunCollection.ReadAll()
175			if err != nil {
176				return nil, err
177			}
178			for _, entry := range beads {
179				rec, err := s.runRecordFromBead(entry)
180				if err != nil {
181					return nil, err
182				}
183				if rec.RunID == "" {
184					continue
185				}
186				runs[rec.RunID] = rec
187			}
188		}
189	
190		legacy, err := s.readLegacyRuns()
191		if err != nil {
192			return nil, err
193		}
194		for _, rec := range legacy {
195			if rec.RunID == "" {
196				continue
197			}
198			if _, ok := runs[rec.RunID]; ok {
199				continue
200			}
201			runs[rec.RunID] = rec
202		}
203	
204		out := make([]RunRecord, 0, len(runs))
205		for _, rec := range runs {
206			out = append(out, rec)
207		}
208		sort.Slice(out, func(i, j int) bool {
209			if out[i].StartedAt.Equal(out[j].StartedAt) {
210				return out[i].RunID < out[j].RunID
211			}
212			return out[i].StartedAt.Before(out[j].StartedAt)
213		})
214		return out, nil
215	}
